export declare const V: unique symbol;
export declare const E: unique symbol;
export declare const F: unique symbol;
import { Remover } from "@hoge1e3/events";
export interface Ref<T> extends ReadonlyRef<T> {
    set(v: T): void;
    value: T;
    [V]: T;
}
export interface RefProxy<T> extends ReadonlyRefProxy<T> {
    [V]: T;
}
export type ChangeEvent<T> = {
    prev: T;
    val: T;
};
export type ChangeEventHandler<T> = (e: ChangeEvent<T>) => void;
export interface ReadonlyRef<T> extends ReadonlyRefProxy<T> {
    get(): T;
    readonly value: T;
    on(event: "change", handler: ChangeEventHandler<T>): Remover;
    fire(event: "change", payload: ChangeEvent<T>): void;
}
export interface ReadonlyRefProxy<T> {
    readonly [V]: T;
    [E]: (h: ChangeEventHandler<T>) => Remover;
    [F](event: "change", payload: ChangeEvent<T>): void;
}
export type RefValue<R> = R extends ReadonlyRefProxy<infer U> ? U : never;
export type RefValues<RS extends readonly ReadonlyRefProxy<unknown>[]> = {
    [K in keyof RS]: RefValue<RS[K]>;
};
export declare function ref<T>(val: T): Ref<T>;
export declare function get<T>(r: RefProxy<T>): T;
export declare function set<T>(r: RefProxy<T>, v: T): void;
export declare function change<T>(r: ReadonlyRefProxy<T>, h: ChangeEventHandler<T>): void;
export declare function computed<RS extends readonly ReadonlyRefProxy<unknown>[], T>(...args: [
    ...RS,
    (...values: RefValues<RS>) => T
]): ReadonlyRef<T>;
export declare function custom<T>(g: () => T, s: (v: T) => void): Ref<T>;
